from game import GameBoard, Piece, Player, get_user_move, is_valid_move, make_move, check_winner

def run():
    board = GameBoard()
    player1 = Player("red")
    player2 = Player("black")

    current_player = player1

    while True:
        print(board)
        move = get_user_move(current_player.color)

        if not is_valid_move(move):
