class GameBoard:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        for i in range(8):
            for j in range((i + (i % 2)) % 2, 8, 2):
                if i < 3:
                    self.board[i][j] = Piece("red")
                elif i > 4:
                    self.board[i][j] = Piece("black")

    def __str__(self):
        result = "   a b c d e f g h\n"
        for i in range(8):
            result += f"{i + 1} | "
            for j in range(8):
                if self.board[i][j]:
                    result += "R" if self.board[i][j].color == "red" else "B"
                else:
                    result += "."
                result += "| "
            result += "\n"
        return result

class Piece:
    def __init__(self, color):
        self.color = color
        self.king = False

class Player:
    def __init__(self, color):
        self.color = color

    def make_move(self, move, board):
        from_pos, to_pos = move.split('-')
        from_i, from_j = int(from_pos[1]) - 1, ord(from_pos[0]) - ord('a')
        to_i, to_j = int(to_pos[1]) - 1, ord(to_pos[0]) - ord('a')

        piece = board.board[from_i][from_j]
        if not piece or piece.color != self.color:
            return False

        # Move the piece
        board.board[from_i][from_j] = None
        board.board[to_i][to_j] = piece

        # Check for kinging
        if (self.color == "red" and to_i == 7) or (self.color == "black" and to_i == 0):
            piece.king = True

        return True

def get_user_move(color):
    move = input(f"Player {color}, enter your move (e.g., e2-e4): ").strip()
    return move

def is_valid_move(move, board):
    from_pos, to_pos = move.split('-')
    from_i, from_j = int(from_pos[1]) - 1, ord(from_pos[0]) - ord('a')
    to_i, to_j = int(to_pos[1]) - 1, ord(to_pos[0]) - ord('a')

    piece = board.board[from_i][from_j]
    if not piece:
        return False

    # Simplified check for valid moves
    if (abs(from_i - to_i) == abs(from_j - to_j)) and (to_i >= 0 and to_i < 8 and to_j >= 0 and to_j < 8):
        return True
    return False

def make_move(move, board):
    from_pos, to_pos = move.split('-')
    from_i, from_j = int(from_pos[1]) - 1, ord(from_pos[0]) - ord('a')
    to_i, to_j = int(to_pos[1]) - 1, ord(to_pos[0]) - ord('a')

    piece = board.board[from_i][from_j]
    if not piece:
        return False

    # Move the piece
    board.board[from_i][from_j] = None
    board.board[to_i][to_j] = piece

    # Check for kinging
    if (piece.color == "red" and to_i == 7) or (piece.color == "black" and to_i == 0):
        piece.king = True

    return True

def check_winner(board):
    red_count = sum(1 for row in board.board for piece in row if piece and piece.color == "red")
    black_count = sum(1 for row in board.board for piece in row if piece and piece.color == "black")

    if red_count == 0:
        return "black"
    elif black_count == 0:
        return "red"
    return None
