# board.py
class Board:
    def __init__(self):
        self.grid = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        for row in range(3):
            for col in range(row % 2, 8, 2):
                self.grid[row][col] = Piece('B')
        for row in range(5, 8):
            for col in range((7 - row) % 2, 8, 2):
                self.grid[row][col] = Piece('W')

    def display(self):
        for row in range(8):
            print(' ' * (7 - row), end='')
            for col in range(8):
                if self.grid[row][col]:
                    print(self.grid[row][col], end=' ')
                else:
                    print('.', end=' ')
            print()

    def move_piece(self, from_pos, to_pos):
        piece = self.grid[from_pos[0]][from_pos[1]]
        if piece:
            self.grid[to_pos[0]][to_pos[1]] = piece
            self.grid[from_pos[0]][from_pos[1]] = None

class Piece:
    def __init__(self, color, is_king=False):
        self.color = color
        self.is_king = is_king

    def __str__(self):
        if self.color == 'B':
            return 'b' if not self.is_king else 'B'
        else:
            return 'w' if not self.is_king else 'W'

if __name__ == "__main__":
    board = Board()
    board.display()
